import { MessageEvent } from '@nitrots/nitro-renderer';
import { ATMOpenParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/ATMOpenParser';

export class ATMOpenMessageEvent extends MessageEvent {
    constructor(callback: (event: ATMOpenMessageEvent) => void) {
        super(callback, ATMOpenParser);
    }

    public getParser(): ATMOpenParser {
        return this.parser as ATMOpenParser;
    }
}
